def forward(self, data, rois):
        assert data.size(1) == self.out_channels
        common_args = {
            "spatial_scale": self.spatial_scale,
            "out_size": self.out_size,
            "out_channels": self.out_channels,
            "group_size": self.group_size,
            "part_size": self.part_size,
            "sample_per_part": self.sample_per_part,
            "trans_std": self.trans_std,
        }

        if self.no_trans:
            offset = data.new_empty(0)
            return deform_roi_pooling(data, rois, offset, **common_args, no_trans=self.no_trans)

        else:
            n = rois.shape[0]
            offset = data.new_empty(0)
            x = deform_roi_pooling(data, rois, offset, **common_args, no_trans=True)
            offset = self.offset_fc(x.view(n, -1))
            offset = offset.view(n, 2, self.out_size[0], self.out_size[1])
            return deform_roi_pooling(data, rois, offset, **common_args, no_trans=self.no_trans)

