def __init__(self, fields, values):
        if isinstance(fields, (str,)):
            fields = fields.replace(',', ' ').split()

        fields = list(fields)
        values = tuple(values)
        if len(set(fields)) != len(fields):
            raise ValueError('Duplicated field names!')

        if len(fields) != len(values):
            raise ValueError('Key/value length not match!')

        self._fields = fields
        self._values = values

gpt_code:
def __init__(self, fields, values):
        if isinstance(fields, (str,)):
            fields = fields.replace(',', ' ').split()

        fields = [*fields]  # Using PEP 448 to immediately unpack into a list.
        values = (*values,)  # Using PEP 448 to immediately unpack into a tuple.

        if len(set(fields)) != len(fields):
            raise ValueError('Duplicated field names!')

        if len(fields) != len(values):
            raise ValueError('Key/value length not match!')

        self._fields = fields
        self._values = values

def test_aeo_carnivore_consumption():
    new_aeo = aeo.AEO()

    search_space = search.SearchSpace(
        n_agents=10,
        n_variables=2,
        **{'lower_bound': [0, 0], 'upper_bound': [10, 10]}
    )

    a = new_aeo._carnivore_consumption(
        *search_space.agents[:2], 0.5
    )

    assert type(a).__name__ == 'Agent'

