                                break

                    except Timeout_t3:
                        pkt = iec104_handler.send_104frame(TESTFR_act)
                        if pkt:
                            sock.send(pkt)
                    finally:
                        timeout_t3.cancel()
                except gevent.Timeout:
                    logger.warning("T1 timed out. (%s)", session.id)
                    logger.info("IEC104 Station disconnected. (%s)", session.id)
                    session.add_event({"type": "CONNECTION_LOST"})
                    iec104_handler.disconnect()
                    break
        except socket.timeout:
            logger.debug("Socket timeout, remote: %s. (%s)", address[0], session.id)
            session.add_event({"type": "CONNECTION_LOST"})
        except socket.error as err:
            if isinstance(err.args, tuple):
                if err.errno == errno.EPIPE:
                    # remote peer disconnected
                    logger.info("IEC104 Station disconnected. (%s)", session.id)
                    session.add_event({"type": "CONNECTION_LOST"})
                else:
                    # determine and handle different error
                    pass
            else:
                print(("socket error ", err))
            iec104_handler.disconnect()
```

### Changes Made (PEP 448 Refactorings):

1. `*address` in the call to `conpot_core.get_session`: A single step of unpacking the `address` tuple into its two components instead of manually accessing `address[0]` and `address[1]`.

2. `*sock.getsockname()` in the call to `conpot_core.get_session`: Unpacking the `sock.getsockname()` tuple directly instead of manually accessing attributes.

3. `*address` in `logger.info`: Unpacking the two elements of the `address` tuple in the log formatting rather than referencing `address[0]` and `address[1]`.

### Count of PEP 448 Adjustments: 3
